// Extract useful info from the scraped HTML
// FIX: n8n v2 webhook body is at $json.body.url
const html = $input.first().json.data || $input.first().json.body || '';

// Strip HTML tags to get text content
const textContent = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 15000);

const aboutPattern = /href=["']([^"']*(?:about|our-story|who-we-are)[^"']*)["']/gi;
const productPattern = /href=["']([^"']*(?:product|collection|shop|catalog|brand)[^"']*)["']/gi;

const aboutLinks = [];
const productLinks = [];
let match;

while ((match = aboutPattern.exec(html)) !== null) {
  aboutLinks.push(match[1]);
}
while ((match = productPattern.exec(html)) !== null) {
  productLinks.push(match[1]);
}

const knownBrands = ['Tom Ford', 'Chanel', 'Dior', 'Gucci', 'Versace', 'YSL', 'Armani',
  'Creed', 'Maison Francis Kurkdjian', 'MFK', 'Parfums de Marly', 'Initio', 'Byredo',
  'Le Labo', 'Amouage', 'Kilian', 'Xerjoff', 'La Mer', 'Charlotte Tilbury',
  'NARS', 'MAC', 'Estee Lauder', 'Burberry', 'Moncler', 'Canada Goose',
  'Jo Malone', 'Dolce & Gabbana', 'Prada', 'Valentino', 'Givenchy', 'Hermes',
  'Bvlgari', 'Bottega Veneta', 'Balenciaga', 'Saint Laurent', 'Celine',
  'Carolina Herrera', 'Montblanc', 'Hugo Boss', 'Calvin Klein', 'Ralph Lauren',
  'Lacoste', 'Coach', 'Kate Spade', 'Michael Kors', 'Tory Burch',
  'Clinique', 'Lancome', 'Shiseido', 'Kiehl', 'Origins', 'Bobbi Brown'];

const brandsFound = knownBrands.filter(brand =>
  textContent.toLowerCase().includes(brand.toLowerCase())
);

const pricePattern = /\$([\d,]+\.?\d{0,2})/g;
const prices = [];
while ((match = pricePattern.exec(textContent)) !== null) {
  prices.push(parseFloat(match[1].replace(',', '')));
}

return [{
  json: {
    url: $('Webhook: Qualify URL').first().json.body.url,
    text_content: textContent,
    brands_found: brandsFound,
    prices_found: prices.slice(0, 50),
    about_links: [...new Set(aboutLinks)].slice(0, 3),
    product_links: [...new Set(productLinks)].slice(0, 10),
    avg_price: prices.length > 0 ? (prices.reduce((a, b) => a + b, 0) / prices.length).toFixed(2) : null
  }
}];

// FIX: n8n Code nodes don't wait for parallel branches automatically.
// Use try-catch — if one branch hasn't fired yet, return [] to skip this execution.
// n8n will re-run this node when the second branch completes.

let scrapedData;
try {
  scrapedData = $('Extract Page Data').first().json;
} catch(e) {
  return [];
}

let catalogResponse;
try {
  catalogResponse = $('Fetch Brand Catalog').first().json;
} catch(e) {
  return [];
}

const catalog = (catalogResponse.records || []).map(r => ({
  brand: r.fields['Brand Name'],
  category: r.fields['Category'],
  price: r.fields['Your Price'] || null,
  status: r.fields['Status'] || 'unknown'
}));

return [{
  json: {
    scraped: scrapedData,
    catalog: catalog
  }
}];

